-- =====================================================================
-- ForêtMap — Migration 07 : QCM scientifiques & jardinage
-- Format calqué sur gl_qcm_questions (ADAPTÉ) : pas de biome ;
-- catégories par thème (sciences / jardinage) ; 4-5 choix ;
-- feedback par choix ; liens vers GLOSSAIRE et FICHES ESPÈCES.
-- Idempotent (INSERT IGNORE, PK stables). Pré-requis : migrations 01-06.
-- =====================================================================

CREATE TABLE IF NOT EXISTS quiz_categories (
  slug varchar(64) NOT NULL,
  nom varchar(180) NOT NULL,
  emoji varchar(16) DEFAULT NULL,
  theme enum('sciences','jardinage') NOT NULL,
  description text DEFAULT NULL,
  order_index int(11) NOT NULL DEFAULT 0,
  created_at datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (slug), KEY idx_quiz_cat_order (order_index)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS quiz_questions (
  question_code varchar(16) NOT NULL,
  categorie_slug varchar(64) NOT NULL,
  numero_dans_categorie int(11) NOT NULL DEFAULT 1,
  question text NOT NULL,
  choix_a text NOT NULL, choix_b text NOT NULL, choix_c text NOT NULL,
  choix_d text DEFAULT NULL, choix_e text DEFAULT NULL,
  reponse_correcte enum('A','B','C','D','E') NOT NULL,
  reponse_texte text DEFAULT NULL,
  niveau enum('college','lycee') NOT NULL DEFAULT 'college',
  difficulte tinyint(3) unsigned DEFAULT NULL,
  difficulte_label varchar(64) DEFAULT NULL,
  feedback_correct text DEFAULT NULL,
  feedback_a text DEFAULT NULL, feedback_b text DEFAULT NULL, feedback_c text DEFAULT NULL,
  feedback_d text DEFAULT NULL, feedback_e text DEFAULT NULL,
  notes_pedagogiques text DEFAULT NULL,
  tags text DEFAULT NULL,
  photo_url varchar(1024) DEFAULT NULL,
  photo_species_id int(10) unsigned DEFAULT NULL,
  photo_source varchar(64) DEFAULT NULL,
  photo_credit text DEFAULT NULL,
  photo_licence varchar(160) DEFAULT NULL,
  photo_licence_url varchar(1024) DEFAULT NULL,
  photo_legende text DEFAULT NULL,
  photo_sujet varchar(255) DEFAULT NULL,
  statut varchar(32) NOT NULL DEFAULT 'actif',
  created_at datetime NOT NULL DEFAULT current_timestamp(),
  updated_at datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (question_code),
  UNIQUE KEY uq_quiz_cat_num (categorie_slug,numero_dans_categorie),
  KEY idx_quiz_cat (categorie_slug), KEY idx_quiz_diff (difficulte), KEY idx_quiz_niveau (niveau),
  KEY idx_quiz_photo_sp (photo_species_id),
  CONSTRAINT fk_quiz_cat FOREIGN KEY (categorie_slug) REFERENCES quiz_categories (slug) ON UPDATE CASCADE,
  CONSTRAINT fk_quiz_photo_sp FOREIGN KEY (photo_species_id) REFERENCES plants (id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Activation idempotente des champs photo (si une version antérieure de la table existe)
ALTER TABLE quiz_questions
  ADD COLUMN IF NOT EXISTS photo_url varchar(1024) DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS photo_species_id int(10) unsigned DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS photo_source varchar(64) DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS photo_credit text DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS photo_licence varchar(160) DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS photo_licence_url varchar(1024) DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS photo_legende text DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS photo_sujet varchar(255) DEFAULT NULL;

CREATE TABLE IF NOT EXISTS quiz_question_tutorials (
  question_code varchar(16) NOT NULL, tutorial_id int(10) unsigned NOT NULL,
  PRIMARY KEY (question_code,tutorial_id), KEY idx_qqt_tuto (tutorial_id),
  CONSTRAINT fk_qqt_q FOREIGN KEY (question_code) REFERENCES quiz_questions (question_code) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT fk_qqt_t FOREIGN KEY (tutorial_id) REFERENCES tutorials (id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS quiz_question_glossary (
  question_code varchar(16) NOT NULL, glossary_code varchar(16) NOT NULL,
  PRIMARY KEY (question_code,glossary_code), KEY idx_qqg_term (glossary_code),
  CONSTRAINT fk_qqg_q FOREIGN KEY (question_code) REFERENCES quiz_questions (question_code) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT fk_qqg_g FOREIGN KEY (glossary_code) REFERENCES glossary_terms (glossary_code) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS quiz_question_species (
  question_code varchar(16) NOT NULL, plant_id int(10) unsigned NOT NULL,
  PRIMARY KEY (question_code,plant_id), KEY idx_qqs_plant (plant_id),
  CONSTRAINT fk_qqs_q FOREIGN KEY (question_code) REFERENCES quiz_questions (question_code) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT fk_qqs_p FOREIGN KEY (plant_id) REFERENCES plants (id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



